package main

import "fmt"

type book struct {
	title string
	pages int
}

func display(b book) {
	fmt.Printf("\"%s\" — %d pages\n", b.title, b.pages)
}

func main() {
	b := book{title: "The Great Gatsby", pages: 180}
	display(b)
}

package main

import (
	"encoding/json"
	"fmt"
)

type Book struct {
	Title string `json:"title"`
	Author string `json:"author"`
	Pages int    `json:"pages"`
}

func main() {
	b := Book{Title: "The Great Gatsby", Author: "F. Scott Fitzgerald", Pages: 180}
	data, err := json.Marshal(b)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println(string(data))
}

